    def start_decision_span(
        self,
        *,
        tool_call: dict[str, Any],
        planner_message: str | None,
        agent_name: str | None,
    ) -> None:
        if not self.enabled:
            return

        try:
            invoice_id = tool_call["args"].get("invoice_id")
            if invoice_id is not None:
                self._ensure_invoice_span(str(invoice_id))
